'use client';

import { SingleImageDrop } from '@/components/dropzone/single-image-drop';

interface AvatarDropzoneInlineProps {
    className?: string;
    onFileSelect?: (file: File | null) => void;
    maxSize?: number;
    defaultImage?: string;
    label?: string;
    description?: string;
}

export function AvatarDropzoneInline({
    className,
    onFileSelect,
    maxSize = 5 * 1024 * 1024,
    defaultImage,
    label = 'Photo',
    description,
}: AvatarDropzoneInlineProps) {
    return (
        <SingleImageDrop
            variant="inline"
            onFile={onFileSelect || (() => {})}
            maxSize={maxSize}
            preview={defaultImage}
            label={label}
            description={description}
            showRemoveButton={true}
            className={className}
        />
    );
}
